"use server";
import { revalidatePath } from "next/cache";
import { getSupabaseServerClient } from "@/lib/supabase/server";
import { fetchProfile } from "@/lib/data";

export async function createSocialLinkAction(formData: FormData) {
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) return { ok: false, error: "Not authenticated" } as const;

  const profile = await fetchProfile();
  if (!profile) return { ok: false, error: "No profile" } as const;

  const payload = {
    profile_id: profile.id,
    platform: String(formData.get("platform") || ""),
    icon_url: String(formData.get("icon_url") || ""),
    url: String(formData.get("url") || ""),
    position: Number(formData.get("position") || 0),
  };
  const { error } = await supabase.from("social_links").insert(payload);
  if (error) return { ok: false, error: error.message } as const;
  revalidatePath("/admin/social-links");
  revalidatePath("/");
  return { ok: true } as const;
}

export async function updateSocialLinkAction(formData: FormData) {
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) return { ok: false, error: "Not authenticated" } as const;
  const id = String(formData.get("id") || "");
  const updates = {
    platform: String(formData.get("platform") || ""),
    icon_url: String(formData.get("icon_url") || ""),
    url: String(formData.get("url") || ""),
    position: Number(formData.get("position") || 0),
  };
  const { error } = await supabase.from("social_links").update(updates).eq("id", id);
  if (error) return { ok: false, error: error.message } as const;
  revalidatePath("/admin/social-links");
  revalidatePath("/");
  return { ok: true } as const;
}

export async function deleteSocialLinkAction(formData: FormData) {
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) return { ok: false, error: "Not authenticated" } as const;
  const id = String(formData.get("id") || "");
  const { error } = await supabase.from("social_links").delete().eq("id", id);
  if (error) return { ok: false, error: error.message } as const;
  revalidatePath("/admin/social-links");
  revalidatePath("/");
  return { ok: true } as const;
}
